import React from 'react';
import type {ISkeleton} from '@lmb-it/kitsconcerto-types';
import {Flex} from '../../_compat'
import {ResponsiveElement, useSeparator} from "../../factory";

type GluestackVariant = 'rounded' | 'sharp' | 'circular';
type PrimeReactShape = 'rectangle' | 'circle' | undefined;


const SkeletonText: React.FC<ISkeleton> = ({
                                               isLoaded,
                                               startColor,
                                               speed,
                                               variant,
                                               container,
                                               ...props
                                           }) => {

    const {cssProps, nativeProps} = useSeparator<Record<any, any>>(props);

    if (isLoaded) {
        return null;
    }

    function mapVariantToPrimeShape(variant?: GluestackVariant): PrimeReactShape {
        switch (variant) {
            case 'circular':
                return 'circle';
            case 'sharp':
                return 'rectangle'; // Square or sharp cornered block
            case 'rounded':
            default:
                return undefined; // Default shape in PrimeReact (rounded rectangle)
        }
    }


    return (

        <Flex {...container}>
            <ResponsiveElement
                cssProps={cssProps}
                nativeProps={{
                    shape: mapVariantToPrimeShape(variant),
                    ...nativeProps
                }}
                as={"Skeleton"}
            />
        </Flex>
    );
};
export default SkeletonText;
